// <<< CUSTOM: Phase 8 — Method-restricted routes for join tables and event logs
impl SapiensModule {
    /// HTTP routes with method restrictions enforced for security compliance.
    ///
    /// - Join tables (user_roles, role_permissions): 405 on PUT/PATCH
    /// - Event logs (audit_logs, security_events, password_history): 405 on DELETE/PUT/PATCH
    pub fn routes_secured(&self) -> Router {
        use axum::middleware;
        self.routes()
            .route_layer(middleware::from_fn(sapiens_method_guard))
    }
}

/// Middleware enforcing HTTP method restrictions on security-sensitive sapiens resources.
///
/// Runs only for matched routes (applied via route_layer), so 404 behavior is unaffected.
async fn sapiens_method_guard(
    req: axum::extract::Request,
    next: axum::middleware::Next,
) -> axum::response::Response {
    use axum::http::{Method, StatusCode};
    use axum::response::IntoResponse;

    let method = req.method().clone();
    let path = req.uri().path().to_owned();

    // Join tables: assign/revoke only — PUT/PATCH would mutate the assignment record
    let is_join_table = path.starts_with("/user_roles") || path.starts_with("/role_permissions");
    if is_join_table && (method == Method::PUT || method == Method::PATCH) {
        return (
            StatusCode::METHOD_NOT_ALLOWED,
            axum::Json(serde_json::json!({
                "success": false,
                "error": "METHOD_NOT_ALLOWED",
                "message": "Join table resources do not support mutation. Use create/delete to manage assignments."
            })),
        ).into_response();
    }

    // Event logs: append-only immutable records — no modifications or deletions
    let is_event_log = path.starts_with("/audit_logs")
        || path.starts_with("/security_events")
        || path.starts_with("/password_history");
    if is_event_log && (method == Method::DELETE || method == Method::PUT || method == Method::PATCH) {
        return (
            StatusCode::METHOD_NOT_ALLOWED,
            axum::Json(serde_json::json!({
                "success": false,
                "error": "METHOD_NOT_ALLOWED",
                "message": "Event log resources are immutable. Records cannot be modified or deleted."
            })),
        ).into_response();
    }

    next.run(req).await
}
